'use client';

import { useEffect, useMemo, useState } from 'react';
import Link from 'next/link';
import { ChevronDown } from 'lucide-react';
import { clsx } from 'clsx';

const STORAGE_KEY = 'docs-sidebar-sections';

function getSectionKey(section) {
  return section.key || section.title.toLowerCase().replace(/[^a-z0-9]+/g, '-').replace(/^-+|-+$/g, '');
}

export function DocsSidebar({
  navigation = [],
  activeHref,
  version,
  className,
  onNavigate,
}) {
  const sectionKeys = useMemo(
    () => navigation.reduce((acc, section) => ({ ...acc, [getSectionKey(section)]: section.defaultExpanded !== false }), {}),
    [navigation]
  );
  const [expandedSections, setExpandedSections] = useState(sectionKeys);

  useEffect(() => {
    try {
      const saved = window.localStorage.getItem(STORAGE_KEY);
      setExpandedSections(saved ? { ...sectionKeys, ...JSON.parse(saved) } : sectionKeys);
    } catch {
      setExpandedSections(sectionKeys);
    }
  }, [sectionKeys]);

  useEffect(() => {
    const activeSection = navigation.find((section) =>
      section.items.some((item) => activeHref === item.href || (item.href !== '/' && activeHref?.startsWith(item.href)))
    );

    if (!activeSection) return;

    const key = getSectionKey(activeSection);
    setExpandedSections((current) => ({ ...current, [key]: true }));
  }, [activeHref, navigation]);

  function toggleSection(key) {
    setExpandedSections((current) => {
      const next = { ...current, [key]: !current[key] };
      try {
        window.localStorage.setItem(STORAGE_KEY, JSON.stringify(next));
      } catch {
        // Ignore storage failures; the current session still reflects the change.
      }
      return next;
    });
  }

  return (
    <aside
      className={clsx(
        'fixed inset-y-0 left-0 z-40 flex w-[272px] flex-col border-r border-brand-border bg-white pt-14 transition-transform duration-200 lg:static lg:z-0 lg:pt-0 lg:shrink-0',
        className
      )}
    >
      <div className="flex flex-1 flex-col overflow-y-auto px-4 py-5">
        {version ? (
          <p className="mb-5 px-2 text-xs font-medium text-brand-text-muted lg:hidden">{version}</p>
        ) : null}

        <nav className="space-y-6">
          {navigation.map((section) => {
            const sectionKey = getSectionKey(section);
            const isExpanded = expandedSections[sectionKey] !== false;

            return (
              <div key={sectionKey}>
                <button
                  type="button"
                  onClick={() => toggleSection(sectionKey)}
                  className="mb-2 flex w-full items-center justify-between rounded-lg px-2 py-1 text-left text-[11px] font-semibold uppercase tracking-wider text-brand-text-muted transition-colors hover:bg-brand-hover hover:text-brand-foreground"
                  aria-expanded={isExpanded}
                >
                  <span>{section.title}</span>
                  <ChevronDown
                    className={clsx('h-3.5 w-3.5 transition-transform duration-200', isExpanded ? 'rotate-0' : '-rotate-90')}
                    aria-hidden
                  />
                </button>
                <div
                  className={clsx(
                    'grid transition-[grid-template-rows,opacity] duration-200 ease-out',
                    isExpanded ? 'grid-rows-[1fr] opacity-100' : 'grid-rows-[0fr] opacity-0'
                  )}
                >
                  <ul className="min-h-0 space-y-0.5 overflow-hidden">
                {section.items.map((item) => {
                  const isActive =
                    activeHref === item.href ||
                    (item.href !== '/' && activeHref?.startsWith(item.href));

                  return (
                    <li key={item.href}>
                      <Link
                        href={item.href}
                        onClick={onNavigate}
                        className={clsx(
                          'block rounded-lg border-l-2 px-2.5 py-2 text-sm transition-colors',
                          isActive
                            ? 'border-brand-primary bg-brand-light font-medium text-brand-primary shadow-sm'
                            : 'border-transparent text-brand-text-light hover:bg-brand-hover hover:text-brand-foreground'
                        )}
                      >
                        {item.label}
                      </Link>
                    </li>
                  );
                })}
                  </ul>
                </div>
              </div>
            );
          })}
        </nav>
      </div>

      <div className="hidden border-t border-brand-border px-4 py-4 lg:block">
        {version ? (
          <p className="px-2 text-xs text-brand-text-muted">{version}</p>
        ) : null}
      </div>
    </aside>
  );
}
