'use client';

import { useState } from 'react';
import { CheckCircle2, MessageSquare, ThumbsDown, ThumbsUp } from 'lucide-react';
import { clsx } from 'clsx';

export function DocsFeedback({ onSubmit, className }) {
  const [choice, setChoice] = useState(null);
  const [comment, setComment] = useState('');
  const [status, setStatus] = useState('idle');
  const [error, setError] = useState('');

  async function handleSubmit(helpful) {
    setChoice(helpful);
    setStatus('submitting');
    setError('');

    try {
      await onSubmit?.({ helpful, comment: comment.trim() });
      setStatus('submitted');
    } catch (err) {
      setStatus('error');
      setError(err?.message || 'Feedback could not be sent.');
    }
  }

  if (status === 'submitted') {
    return (
      <div className={clsx('mt-12 rounded-xl border border-brand-border bg-white p-5 shadow-soft', className)}>
        <div className="flex items-center gap-2 text-sm font-medium text-brand-primary">
          <CheckCircle2 className="h-4 w-4" aria-hidden />
          Thanks for helping improve this page.
        </div>
      </div>
    );
  }

  return (
    <section className={clsx('mt-12 rounded-xl border border-brand-border bg-white p-5 shadow-soft', className)} aria-label="Page feedback">
      <div className="flex items-start gap-3">
        <span className="mt-0.5 flex h-9 w-9 shrink-0 items-center justify-center rounded-full bg-brand-light text-brand-primary">
          <MessageSquare className="h-4 w-4" aria-hidden />
        </span>
        <div className="min-w-0 flex-1">
          <h2 className="text-base font-semibold text-brand-dark">Was this page helpful?</h2>
          <p className="mt-1 text-sm text-brand-text-muted">Send a quick signal so the documentation can keep improving.</p>

          <textarea
            value={comment}
            onChange={(event) => setComment(event.target.value)}
            placeholder="Optional: what should be clearer?"
            className="mt-4 min-h-20 w-full rounded-lg border border-brand-border bg-[#fafafa] px-3 py-2 text-sm text-brand-foreground placeholder:text-brand-text-muted focus:border-brand-primary focus:outline-none focus:ring-2 focus:ring-brand-primary/20"
          />

          <div className="mt-3 flex flex-wrap items-center gap-2">
            <button
              type="button"
              onClick={() => handleSubmit(true)}
              disabled={status === 'submitting'}
              className={clsx(
                'inline-flex items-center gap-2 rounded-lg border px-3 py-2 text-sm font-medium transition-colors disabled:cursor-not-allowed disabled:opacity-60',
                choice === true ? 'border-brand-primary bg-brand-light text-brand-primary' : 'border-brand-border bg-white text-brand-foreground hover:bg-brand-hover'
              )}
            >
              <ThumbsUp className="h-4 w-4" aria-hidden />
              Yes
            </button>
            <button
              type="button"
              onClick={() => handleSubmit(false)}
              disabled={status === 'submitting'}
              className={clsx(
                'inline-flex items-center gap-2 rounded-lg border px-3 py-2 text-sm font-medium transition-colors disabled:cursor-not-allowed disabled:opacity-60',
                choice === false ? 'border-brand-primary bg-brand-light text-brand-primary' : 'border-brand-border bg-white text-brand-foreground hover:bg-brand-hover'
              )}
            >
              <ThumbsDown className="h-4 w-4" aria-hidden />
              No
            </button>
            {error ? <p className="text-sm text-red-600">{error}</p> : null}
          </div>
        </div>
      </div>
    </section>
  );
}
