'use client';

import { useEffect, useRef, useState } from 'react';
import Image from 'next/image';
import Link from 'next/link';
import { Menu, Search, X } from 'lucide-react';
import { clsx } from 'clsx';
import { DocsSearchResults } from '../DocsSearchResults';

export function DocsTopBar({
  branding = {},
  version,
  searchPlaceholder,
  onSearch,
  searchResults = [],
  onMenuToggle,
  mobileNavOpen,
  adminHref,
}) {
  const { logoPath, brandName = 'Webfudge Systems', homeHref = '/' } = branding;
  const [query, setQuery] = useState('');
  const [searchOpen, setSearchOpen] = useState(false);
  const [mobileSearchOpen, setMobileSearchOpen] = useState(false);
  const searchRef = useRef(null);

  // Debounced search
  useEffect(() => {
    const timer = setTimeout(() => {
      if (onSearch) onSearch(query);
      setSearchOpen(query.trim().length >= 2);
    }, 280);
    return () => clearTimeout(timer);
  }, [query, onSearch]);

  // Close on outside click
  useEffect(() => {
    function handleClickOutside(event) {
      if (searchRef.current && !searchRef.current.contains(event.target)) {
        setSearchOpen(false);
      }
    }
    document.addEventListener('mousedown', handleClickOutside);
    return () => document.removeEventListener('mousedown', handleClickOutside);
  }, []);

  const searchPanel = (
    <>
      <label className="relative w-full max-w-md">
        <Search className="pointer-events-none absolute left-3 top-1/2 h-4 w-4 -translate-y-1/2 text-brand-text-muted" />
        <input
          type="search"
          placeholder={searchPlaceholder || 'Search documentation…'}
          value={query}
          onChange={(e) => setQuery(e.target.value)}
          onFocus={() => query.trim().length >= 2 && setSearchOpen(true)}
          className={clsx(
            'h-9 w-full rounded-lg border border-brand-border bg-[#fafafa] pl-9 pr-3 text-sm',
            'text-brand-foreground placeholder:text-brand-text-muted',
            'focus:border-brand-primary focus:outline-none focus:ring-2 focus:ring-brand-primary/20'
          )}
        />
      </label>
      {searchOpen && (
        <DocsSearchResults
          results={searchResults}
          query={query}
          onClose={() => { setSearchOpen(false); setQuery(''); setMobileSearchOpen(false); }}
          className="max-w-md"
        />
      )}
    </>
  );

  return (
    <header className="sticky top-0 z-40 border-b border-brand-border bg-white/95 backdrop-blur-sm">
      <div className="flex h-14 items-center gap-4 px-4 lg:px-6">
        <button
          type="button"
          onClick={onMenuToggle}
          className="inline-flex h-9 w-9 items-center justify-center rounded-lg border border-brand-border text-brand-foreground hover:bg-brand-hover lg:hidden"
          aria-label={mobileNavOpen ? 'Close menu' : 'Open menu'}
        >
          {mobileNavOpen ? <X className="h-5 w-5" /> : <Menu className="h-5 w-5" />}
        </button>

        <Link href={homeHref} className="flex shrink-0 items-center gap-2.5 min-w-0">
          {logoPath ? (
            <Image
              src={logoPath}
              alt=""
              width={28}
              height={28}
              className="h-7 w-7 shrink-0 rounded-md object-contain"
            />
          ) : (
            <span className="flex h-7 w-7 shrink-0 items-center justify-center rounded-md bg-brand-primary text-xs font-bold text-white">
              W
            </span>
          )}
          <span className="truncate text-sm font-semibold text-brand-dark">{brandName}</span>
        </Link>

        <div ref={searchRef} className="hidden flex-1 relative justify-center md:flex">
          {searchPanel}
        </div>

        <div className="ml-auto flex items-center gap-2 shrink-0">
          <button
            type="button"
            onClick={() => {
              setMobileSearchOpen((open) => !open);
              setSearchOpen(query.trim().length >= 2);
            }}
            className="inline-flex h-9 w-9 items-center justify-center rounded-lg border border-brand-border text-brand-foreground hover:bg-brand-hover md:hidden"
            aria-label="Search documentation"
          >
            <Search className="h-4 w-4" />
          </button>
          {version ? (
            <span className="hidden rounded-full border border-brand-border bg-brand-light px-2.5 py-1 text-xs font-medium text-brand-text-light sm:inline-block">
              {version}
            </span>
          ) : null}
          {adminHref ? (
            <Link
              href={adminHref}
              className="hidden rounded-lg border border-brand-border bg-white px-3 py-1.5 text-xs font-medium text-brand-foreground hover:bg-brand-hover sm:inline-block"
            >
              Manage Docs
            </Link>
          ) : null}
        </div>
      </div>
      {mobileSearchOpen ? (
        <div ref={searchRef} className="relative border-t border-brand-border px-4 py-3 md:hidden">
          {searchPanel}
        </div>
      ) : null}
    </header>
  );
}
