import { AlertTriangle, Info, Lightbulb } from 'lucide-react';
import { clsx } from 'clsx';

const VARIANTS = {
  info: {
    icon: Info,
    wrapper: 'border-blue-200 bg-blue-50/80',
    title: 'text-blue-900',
    body: 'text-blue-800/90',
    iconClass: 'text-blue-600',
  },
  warning: {
    icon: AlertTriangle,
    wrapper: 'border-amber-200 bg-amber-50/80',
    title: 'text-amber-900',
    body: 'text-amber-900/90',
    iconClass: 'text-amber-600',
  },
  tip: {
    icon: Lightbulb,
    wrapper: 'border-emerald-200 bg-emerald-50/80',
    title: 'text-emerald-900',
    body: 'text-emerald-900/90',
    iconClass: 'text-emerald-600',
  },
};

export function DocsCallout({ variant = 'info', title, children }) {
  const config = VARIANTS[variant] || VARIANTS.info;
  const Icon = config.icon;

  return (
    <div className={clsx('my-6 flex gap-3 rounded-xl border p-4', config.wrapper)}>
      <Icon className={clsx('mt-0.5 h-5 w-5 shrink-0', config.iconClass)} aria-hidden />
      <div className="min-w-0">
        {title ? <p className={clsx('mb-1 text-sm font-semibold', config.title)}>{title}</p> : null}
        <div className={clsx('text-sm leading-relaxed', config.body)}>{children}</div>
      </div>
    </div>
  );
}
