import Link from 'next/link';
import { clsx } from 'clsx';

export function DocsAppCard({ badge, title, description, port, href, className }) {
  const content = (
    <>
      {badge ? (
        <p className="text-[11px] font-bold uppercase tracking-widest text-brand-primary">{badge}</p>
      ) : null}
      <h3 className="mt-2 text-base font-semibold text-brand-dark">{title}</h3>
      {description ? (
        <p className="mt-2 text-sm leading-relaxed text-brand-text-light">{description}</p>
      ) : null}
      {port ? (
        <p className="mt-4 font-mono text-xs text-brand-text-muted">{port}</p>
      ) : null}
    </>
  );

  const cardClass = clsx(
    'rounded-xl border border-brand-border bg-white p-5 shadow-soft transition-shadow hover:shadow-card-hover',
    href && 'block hover:border-brand-primary/30',
    className
  );

  if (href) {
    return (
      <Link href={href} className={cardClass}>
        {content}
      </Link>
    );
  }

  return <div className={cardClass}>{content}</div>;
}
