'use client';

import Link from 'next/link';
import { AppWindow, BookOpen, FileText, SearchX } from 'lucide-react';
import { clsx } from 'clsx';

function SearchResultIcon({ page }) {
  const value = `${page.category || ''} ${page.application?.name || ''}`.toLowerCase();
  const Icon = value.includes('getting') || value.includes('started')
    ? BookOpen
    : value.includes('application') || value.includes('app')
      ? AppWindow
      : FileText;

  return <Icon className="mt-0.5 h-4 w-4 shrink-0 text-brand-text-muted" aria-hidden />;
}

function highlightMatch(text = '', query = '') {
  if (!text || !query) return text;

  const safeQuery = query.trim().replace(/[.*+?^${}()|[\]\\]/g, '\\$&');
  if (!safeQuery) return text;

  const parts = text.split(new RegExp(`(${safeQuery})`, 'ig'));
  return parts.map((part, index) =>
    part.toLowerCase() === query.trim().toLowerCase() ? (
      <mark key={`${part}-${index}`} className="rounded bg-brand-light px-0.5 text-brand-primary">
        {part}
      </mark>
    ) : (
      part
    )
  );
}

/**
 * Search results dropdown panel.
 *
 * @param {{ results: Array, query: string, onClose: () => void, className?: string }} props
 */
export function DocsSearchResults({ results = [], query = '', onClose, className }) {
  if (!query || query.trim().length < 2) return null;

  return (
    <div
      className={clsx(
        'absolute left-0 right-0 top-full z-50 mt-1 overflow-hidden rounded-xl border border-brand-border bg-white shadow-card transition-all duration-150 ease-out',
        'motion-safe:animate-[docs-search-enter_150ms_ease-out]',
        className
      )}
    >
      {results.length === 0 ? (
        <div className="flex flex-col items-center gap-2 px-4 py-8 text-center text-brand-text-muted">
          <SearchX className="h-8 w-8 opacity-40" />
          <p className="text-sm">No results for <strong>&ldquo;{query}&rdquo;</strong></p>
        </div>
      ) : (
        <ul className="max-h-80 divide-y divide-brand-border overflow-y-auto">
          {results.map((page) => (
            <li key={page.slug}>
              <Link
                href={`/docs/${page.slug}`}
                onClick={onClose}
                className="flex items-start gap-3 px-4 py-3 text-sm transition-colors hover:bg-brand-hover"
              >
                <SearchResultIcon page={page} />
                <div className="min-w-0">
                  <p className="font-medium text-brand-dark truncate">{highlightMatch(page.title, query)}</p>
                  {page.snippet || page.description ? (
                    <p className="text-brand-text-muted line-clamp-2">{highlightMatch(page.snippet || page.description, query)}</p>
                  ) : null}
                  {page.category ? (
                    <p className="mt-0.5 text-xs text-brand-text-muted">
                      {page.application?.name ? `${page.application.name} · ` : ''}{page.category}
                    </p>
                  ) : null}
                </div>
              </Link>
            </li>
          ))}
        </ul>
      )}
    </div>
  );
}
